const PROCESSING_FEE = 5;
const BLOCK_OF_THREE_DISCOUNT = 15;
const BLOCK_SIZE = 3;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const ITEM_BASE_PRICES: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const MAIN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion"]);
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };
type Customer = { yearsWithMHPCO?: number };
type Scenario = {
  customer?: Customer;
  steps: { op: string; items: Item[] }[];
};

function countItemsByType(items: Item[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
}

function basePremiumForComponentGroup(type: string, count: number): number {
  const unitPrice = ITEM_BASE_PRICES[type];
  const subtotal = count * unitPrice;
  const discount = count === BLOCK_SIZE ? BLOCK_OF_THREE_DISCOUNT : 0;
  return subtotal - discount;
}

function computePolicyBase(items: Item[]): number {
  const itemCountsByType = countItemsByType(items);
  let basePremium = 0;
  for (const [type, count] of itemCountsByType.entries()) {
    if (COMPONENT_TYPES.has(type)) {
      basePremium += basePremiumForComponentGroup(type, count);
    } else {
      basePremium += count * ITEM_BASE_PRICES[type];
    }
  }
  return basePremium;
}

function computeFirstInsuranceSurcharge(items: Item[]): number {
  let surcharge = 0;
  for (const item of items) {
    if (MAIN_ITEM_TYPES.has(item.type)) {
      surcharge += ITEM_BASE_PRICES[item.type] * FIRST_INSURANCE_RATE;
    }
  }
  return surcharge;
}

function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
  const years = customer.yearsWithMHPCO ?? 0;
  if (years >= LOYALTY_YEARS_THRESHOLD) {
    return policyBase * LOYALTY_DISCOUNT_RATE;
  }
  return 0;
}

export function runScenario(scenario: unknown): unknown {
  const s = scenario as Scenario;
  const customer = s.customer ?? { yearsWithMHPCO: 0 };
  const items = s.steps[0].items;

  const policyBase = computePolicyBase(items);
  const firstInsurance = computeFirstInsuranceSurcharge(items);
  const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);

  const premium = policyBase + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
  return { results: [{ premium }] };
}
